      # Decode a parsed JSON value into the concrete variant selected by the
      # "type" discriminator. An unknown or absent discriminator
      # (or a non-Hash value) returns the value unchanged.
      def self.decode(value)
        return value unless value.is_a?(Hash)
        raw = value[DISCRIMINATOR.to_sym]
        raw = value[DISCRIMINATOR] if raw.nil?
        variant = MAPPING[raw.to_s]
        return value if variant.nil?
        klass = Models.const_get(variant)
        attrs = {}
        klass.members.each do |member|
          if value.key?(member)
            attrs[member] = value[member]
          elsif value.key?(member.to_s)
            attrs[member] = value[member.to_s]
          end
        end
        klass.new(**attrs)
      rescue NameError, ArgumentError
        value
      end
    end

